import sys
from functools import lru_cache

def solve():
    input_data = sys.stdin.read().split()
    n = int(input_data[0])
    A = list(map(int, input_data[1:n+1]))

    @lru_cache(maxsize=None)
    def wins(l, r, last):
        # Returns True if current player wins
        moves = []
        if l <= r:
            if A[l] > last:
                moves.append((l+1, r, A[l]))
            if A[r] > last and r != l:
                moves.append((l, r-1, A[r]))
        if not moves:
            return False
        for state in moves:
            if not wins(*state):
                return True
        return False

    if wins(0, n-1, -1):
        print("Alice")
    else:
        print("Bob")

solve()

